mapper.update:
UPDATE waitlist_order
SET refund_amount = #{refundAmount}, refund_time = #{refundTime}
WHERE id = #{id}

UPDATE waitlist_passenger
SET locked_seat_id = #{seatId}, locked_seat_no = #{seatNo}
WHERE waitlist_id = #{waitlistId} AND passenger_id = #{passengerId}

mapper.select:

WHERE w.flight_id = #{flightId}
  AND w.cabin_class = #{cabinClass}
  AND w.status = 'WAITING'
ORDER BY w.paid_at ASC, w.id ASC
